#include <bits/stdc++.h>
using namespace std;
int h,n,s[502],dp[502][45003];
int main(){
    scanf("%d%d",&h,&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&s[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=h;j++)
            if(j>=s[i])
                dp[i][j]=max(dp[i-1][j],dp[i-1][j-s[i]]+s[i]);
            else
                dp[i][j]=dp[i-1][j];
    printf("%d",dp[n][h]);
    return 0;
}
